require "property.BaseProperty"

HidingProperty = class("HidingProperty", BaseProperty)

function HidingProperty:onPlayerUsed(player, target, damage)
    local time = self.config.duration
    if self.config.duration < 0 then
        time = 10000
    end
    player:addEffect(PotionID.INVISIBILITY, time, 1)
end

return HidingProperty